checker_dsl:
EXISTS (`literal L`) {
  AND {
    (`L is a Java Literal`),
    (`L is not a CharacterLiteral`),
    EXISTS (`integer indexStart IS`) {
      EXISTS (`integer codePoint CP`) {
        AND {
          (`the string representation of L at index IS has Unicode code point CP`),
          OR {
            AND {
              (`CP < 32`),
              NOT { OR {
                (`CP = 9`),
                (`CP = 10`),
                (`CP = 12`),
                (`CP = 13`)
              } }
            },
            (`CP = 127`),
            (`CP = 8203`)
          }
        }
      }
    },
    EXISTS (`integer charIndex CI`, `integer codePoint CP2`) {
      AND {
        (`the indexStart value of L equals CI`),
        (`the string representation of L at index CI has Unicode code point CP2`)
      }
    }
  }
}
